#include <bits/stdc++.h>
using namespace std;

class FoodRatings {
public:
    FoodRatings(vector<string>& foods, vector<string>& cuisines, vector<int>& ratings) {
        int n = foods.size();
        for (int i = 0; i < n; ++i) {
            foodToCuisine[foods[i]] = cuisines[i];
            foodToRating[foods[i]] = ratings[i];
            cuisineToFoods[cuisines[i]].emplace(ratings[i], foods[i]);
        }
    }

    void changeRating(string food, int newRating) {
        string cuisine = foodToCuisine[food];
        int oldRating = foodToRating[food];
        foodToRating[food] = newRating;
        cuisineToFoods[cuisine].emplace(newRating, food);
    }

    string highestRated(string cuisine) {
        while (true) {
            auto [rating, food] = *cuisineToFoods[cuisine].rbegin();
            if (foodToRating[food] == rating) {
                return food;
            }
            cuisineToFoods[cuisine].erase(prev(cuisineToFoods[cuisine].end()));
        }
    }

private:
    unordered_map<string, string> foodToCuisine;
    unordered_map<string, int> foodToRating;
    unordered_map<string, set<pair<int, string>>> cuisineToFoods;
};
```
efficiency: HIGH
time complexity: O(log N) for changeRating and highestRated
space complexity: O(N)
energy implications: LOW
explanation: Uses a set per cuisine to keep foods sorted by (-rating, food) so the highest rated lexicographically smallest food is always at the end. changeRating inserts the new entry and leaves the stale one; highestRated lazily removes stale entries by checking the current rating.

